        // Minimal parser for [1,2,3] format
        vector<int> nums;
        stringstream ss(line.substr(1, line.size() - 2));
        string temp;
        while (getline(ss, temp, ',')) nums.push_back(stoi(temp));

        next_permutation(nums.begin(), nums.end());

