#include <stdio.h>
#include <stdlib.h>
#include <string.h>

void reverse(int* nums, int start, int end) {
    while (start < end) {
        int temp = nums[start];
        nums[start] = nums[end];
        nums[end] = temp;
        start++; end--;
    }
}

void nextPermutation(int* nums, int numsSize) {
    int i = numsSize - 2;
    while (i >= 0 && nums[i] >= nums[i+1]) i--;
    if (i >= 0) {
        int j = numsSize - 1;
        while (nums[j] <= nums[i]) j--;
        int temp = nums[i];
        nums[i] = nums[j];
        nums[j] = temp;
    }
    reverse(nums, i + 1, numsSize - 1);
}

int main() {
    char buffer[1024];
    if (fgets(buffer, sizeof(buffer), stdin)) {
        int nums[100];
        int numsSize = 0;
        char* token = strtok(buffer + 1, ",]");
        while (token != NULL && numsSize < 100) {
            nums[numsSize++] = atoi(token);
            token = strtok(NULL, ",]");
        }
        nextPermutation(nums, numsSize);
        printf("[");
        for (int i = 0; i < numsSize; i++) {
            printf("%d%s", nums[i], (i == numsSize - 1 ? "" : ","));
        }
        printf("]\n");
    }
    return 0;
}
